+#[repr(align(8))]
+struct AlignedShadowStorage([u8; 256]);
+
+impl AlignedShadowStorage {
+    fn zeroed() -> Self {
+        Self([0; 256])
+    }
+
+    fn as_mut_void(&mut self) -> *mut c_void {
+        self.0.as_mut_ptr().cast()
+    }
